    private void btnCalculateActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnCalculateActionPerformed
        String num1 = tfFirstNum.getText().trim();
        String num2 = tfSecondNum.getText().trim();
        String operation = cmbOperation.getSelectedItem().toString();
        if (tfFirstNum.getText().isEmpty() || tfSecondNum.getText().isEmpty()) {
            JOptionPane.showMessageDialog(this, "Please fill out all fields.",
                    "Incomplete Equation", JOptionPane.ERROR_MESSAGE);
        } else if (!isBinary(num1) || !isBinary(num2)) {
            JOptionPane.showMessageDialog(this, "Inputs must be binary numbers (0 or 1 only).",
                    "Invalid Input", JOptionPane.ERROR_MESSAGE);
        } else {        
            switch (operation) {
                case "+":
                    if (!isBinary(num1) || !isBinary(num2)) {
                        JOptionPane.showMessageDialog(this, "Inputs must be binary numbers (0 or 1 only).", "Invalid Input", JOptionPane.ERROR_MESSAGE);
                    } else {
                        // Ensure both numbers have the same length by padding with zeros
                        int maxLength = Math.max(num1.length(), num2.length());
                        num1 = padLeftZeros(num1, maxLength);
                        num2 = padLeftZeros(num2, maxLength);

                        System.out.println("---Addition Operation---\n");
                        addBinaryNumbers(num1, num2);
                    }
                    break;
                case "*":
                    if (!isUnary(num1) || !isUnary(num2)) {
                        JOptionPane.showMessageDialog(this, "Inputs must be unary numbers (1 only).", "Invalid Input", JOptionPane.ERROR_MESSAGE);
                    } else {
                        System.out.println("---Multiplication Operation---\n");
                        multiplyBinaryNumbers(num1, num2);
                    }
                    break;
                default:
                    JOptionPane.showMessageDialog(this, "Please double-check all text fields.",
                            "Incomplete Equation", JOptionPane.ERROR_MESSAGE);
                    break;
            }
        }
    }//GEN-LAST:event_btnCalculateActionPerformed

    private String addBinaryNumbers(String num1, String num2) {
        String equation = "B" + num1 + "+" + num2 + "B";
        char[] tape = equation.toCharArray();
        int head = 1;  
        String state = "q0"; 
        String direction ="R";
        int countSteps = 0;
        
        //Get decimal numbers of the binary numbers
        int decimalNum1 = Integer.parseInt(num1, 2);
        int decimalNum2 = Integer.parseInt(num2, 2);

        //Set Initial Tape
        String initialTapeDiagram = getInputTape(equation);
        taInitialTape.setText(initialTapeDiagram);
        
        System.out.println("Inputs: " + num1 + " " + "+" + " " + num2);
        System.out.println("Inputs in decimals: " + decimalNum1 + " " + "+" + " " + decimalNum2 + "\n");
      
        while (true) {
            char currentSymbol = tape[head]; 
            System.out.println("Tape: " + new String(tape));
            System.out.print("Î´("+ state + ", " + currentSymbol  + ")");
            
            switch (state) {
                case "q0": 
                    if (currentSymbol == 'B') {
                    	state = "q1"; 
                        head--;
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                        
                    } else {
                        head++;
                        direction ="R";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                    }
                    System.out.println("");
                    break;

                case "q1": 
                    if (currentSymbol == '0') {
                        tape[head] = '1'; 
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", 1, " + direction + ")");
                    } else if (currentSymbol == '1') {
                        tape[head] = '0'; 
                        state = "q2";
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", 0, " + direction + ")");
                    } else if (currentSymbol == '+') {
                        tape[head] = 'B';                        
                        state = "q4"; 
                        head++; 
                        direction ="R";
                        System.out.println(" -> Î´("+ state + ", B, " + direction + ")");
                    } else {
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                    }
                    System.out.println("");
                    break;

                case "q2": 
                    if (currentSymbol == '+') {                       
                        state = "q3"; 
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                    } else {
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                    }
                    System.out.println("");
                    break;
                    
                case "q3": 
                    if (currentSymbol == '0') {
                        tape[head] = '1';                        
                        state = "q0"; 
                        head++;
                        direction ="R";
                        System.out.println(" -> Î´("+ state + ", 1, " + direction + ")");
                    } else if (currentSymbol == '1') {
                        tape[head] = '0'; 
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", 0, " + direction + ")");
                    } else if (currentSymbol == 'B') {
                        tape[head] = '1'; 
                        head++; 
                        state = "q0"; 
                        direction ="R";
                        System.out.println(" -> Î´("+ state + ", 1, " + direction + ")");
                    } else {
                        head--; 
                        direction ="L";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                    }
                    System.out.println("");
                    break;
                    
                case "q4": 
                    if (currentSymbol == '1') {
                        tape[head] = 'B';
                        head++; 
                        direction ="R";
                        System.out.println(" -> Î´("+ state + ", B, " + direction + ")");
                    } else if (currentSymbol == 'B') {
                        state = "q5";
                        System.out.println(" -> Î´("+ state + ", " + "HALT"  + ")");
                    } else {
                        head++; 
                        direction ="R";
                        System.out.println(" -> Î´("+ state + ", " + currentSymbol  + ", " + direction + ")");
                    }
                    System.out.println("");
                    break;  
            }
            if (state.equals("q5")) {
                break;
            }
            countSteps++;
        }
        //Final State
        String finalTape = new String(tape);
        System.out.println("Final Tape: " + finalTape);
        
        String finalTapeDiagram = getInputTape(finalTape);
        taFinalTape.setText(finalTapeDiagram);
        
        StringBuilder binarySum = new StringBuilder();
        for (char c : tape) {
            if (c == '0' || c == '1') {
                binarySum.append(c);
            }
        }
        String resultText = "";
        int sum = Integer.parseInt(binarySum.toString(), 2);
        
        //Print results in console
        System.out.println("Equation: "+num1+"["+decimalNum1+"] + "+num2+"["+decimalNum2+"] = "+binarySum+"["+sum+"]");
        System.out.println("Addition Result in Decimal: " + sum);
        System.out.println("Addition Result in Binary: " + binarySum.toString());
        System.out.println("Steps: "+ countSteps + "\n");
        
        //Show results in GUI
        resultText += "Equation: "+num1+"["+decimalNum1+"] + "+num2+"["+decimalNum2+"] = "+binarySum+"["+sum+"]\n";
        resultText += "Addition Result in Decimal: " + sum + "\n";
        resultText += "Addition Result in Binary: " + binarySum.toString() + "\n";
        resultText += "Steps: "+ countSteps + "\n";
        taResult.setText(resultText);
        
        return null;
    }
    
