    private boolean isBinary(String num) {
        return num.matches("[01]+");
    }
    
    private boolean isUnary(String num) {
        return num.matches("[1]+");
    }
    
    private int getDecimalOfUnary(String num){
        int decimalNum = 0;
        for (int i = 0; i < num.length(); i++){
            decimalNum++;
        }
        return decimalNum;
    }
    
    private static char[] extendTape(char[] tape, boolean addAtEnd) {
        char[] newTape = new char[tape.length + 1];
        if (addAtEnd) {
            System.arraycopy(tape, 0, newTape, 0, tape.length);
            newTape[tape.length] = 'B';
        } else {
            System.arraycopy(tape, 0, newTape, 1, tape.length);
            newTape[0] = 'B';
        }
        return newTape;
    }
    
    private static String padLeftZeros(String binary, int length) {
        StringBuilder paddedBinary = new StringBuilder();
        for (int i = binary.length(); i < length; i++) {
            paddedBinary.append("0");
        }
        paddedBinary.append(binary);
        return paddedBinary.toString();
    }
    
    private static String getInputTape(String equation){
        char[] inputTape = equation.toCharArray();
        String tape = "";
        for (int i=0; i < equation.length(); i++){
            if (i == equation.length()-1)
                tape += inputTape[i];
            else
                tape += inputTape[i]+" | ";
        }
        return tape;
    }

